To create a smooth snake game in C that uses images to animate the whole level, you'll need to use a library that provides graphics capabilities. One popular option is SDL (Simple DirectMedia Layer). Here's a basic outline of how you can implement the game:

**Prerequisites:**

1. Install SDL library: You can download the SDL library from the official website and follow the installation instructions for your platform.
2. Familiarize yourself with C programming and basic game development concepts.

**Game Structure:**

1. **Game Loop:** The game loop will run continuously until the game is over. It will handle user input, update the game state, and render the game screen.
2. **Game State:** The game state will store the current state of the game, including the snake's position, direction, and score.
3. **Graphics:** You'll use SDL to render the game screen, including the snake, food, and walls.

**Code Structure:**

Here's a basic structure for your game:
```c
#include <SDL2/SDL.h>
#include <SDL2/SDL_image.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

// Define constants
#define SCREEN_WIDTH 640
#define SCREEN_HEIGHT 480
#define SNAKE_SPEED 10
#define FOOD_SPAWN_RATE 100

// Define game state
typedef struct {
    int x, y; // Snake's position
    int dir; // Snake's direction (0: up, 1: right, 2: down, 3: left)
    int score;
    int length;
    int food_x, food_y; // Food position
} GameState;

// Define game functions
void init_game();
void update_game(GameState* state);
void render_game(GameState* state);
void handle_input(GameState* state);

int main(int argc, char* argv[]) {
    // Initialize SDL
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, SDL_WINDOW_SHOWN);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Initialize game state
    GameState state;
    state.x = SCREEN_WIDTH / 2;
    state.y = SCREEN_HEIGHT / 2;
    state.dir = 0;
    state.score = 0;
    state.length = 1;
    state.food_x = rand() % SCREEN_WIDTH;
    state.food_y = rand() % SCREEN_HEIGHT;

    // Main game loop
    while (true) {
        // Handle input
        handle_input(&state);

        // Update game state
        update_game(&state);

        // Render game screen
        render_game(&state);

        // Update screen
        SDL_RenderPresent(renderer);

        // Check for quit event
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                break;
            }
        }
    }

    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}

void init_game() {
    // Initialize SDL
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, SDL_WINDOW_SHOWN);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
}

void update_game(GameState* state) {
    // Update snake position
    switch (state->dir) {
        case 0: // Up
            state->y -= SNAKE_SPEED;
            break;
        case 1: // Right
            state->x += SNAKE_SPEED;
            break;
        case 2: // Down
            state->y += SNAKE_SPEED;
            break;
        case 3: // Left
            state->x -= SNAKE_SPEED;
            break;
    }

    // Check for collision with walls or self
    if (state->x < 0 || state->x >= SCREEN_WIDTH || state->y < 0 || state->y >= SCREEN_HEIGHT || state->x == state->food_x && state->y == state->food_y) {
        // Game over
        printf("Game Over!\n");
        exit(0);
    }

    // Check for food
    if (state->x == state->food_x && state->y == state->food_y) {
        state->score++;
        state->length++;
        state->food_x = rand() % SCREEN_WIDTH;
        state->food_y = rand() % SCREEN_HEIGHT;
    }
}

void render_game(GameState* state) {
    // Clear screen
    SDL_SetRenderDrawColor(renderer, 0, 0, 0, 255);
    SDL_RenderClear(renderer);

    // Draw snake
    SDL_Rect snake_rect = {state->x, state->y, 10, 10};
    SDL_SetRenderDrawColor(renderer, 255, 255, 255, 255);
    SDL_RenderFillRect(renderer, &snake_rect);

    // Draw food
    SDL_Rect food_rect = {state->food_x, state->food_y, 10, 10};
    SDL_SetRenderDrawColor(renderer, 255, 0, 0, 255);
    SDL_RenderFillRect(renderer, &food_rect);

    // Draw score
    SDL_SetRenderDrawColor(renderer, 255, 255, 255, 255);
    SDL_RenderDrawLine(renderer, 0, 0, SCREEN_WIDTH, 0);
    SDL_RenderDrawLine(renderer, 0, 0, 0, SCREEN_HEIGHT);
    SDL_RenderDrawLine(renderer, SCREEN_WIDTH, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
    SDL_RenderDrawLine(renderer, 0, SCREEN_HEIGHT, SCREEN_WIDTH, SCREEN_HEIGHT);
    SDL_RenderDrawText(renderer, "Score: %d", state->score, 10, 10);

    // Update screen
    SDL_RenderPresent(renderer);
}

void handle_input(GameState* state) {
    // Get user input
    SDL_Event event;
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_KEYDOWN) {
            switch (event.key.keysym.sym) {
                case SDLK_UP:
                    state->dir = 0;
                    break;
                case SDLK_RIGHT:
                    state->dir = 1;
                    break;
                case SDLK_DOWN:
                    state->dir = 2;
                    break;
                case SDLK_LEFT:
                    state->dir = 3;
                    break;
            }
        }
    }
}
```
