function checkPrimes(arr) {
  for (let i = 0; i < arr.length; i++) {
    let num = arr[i];
    if (isPrime(num)) {
      console.log(`Found prime number: ${num}`);
    }
  }
}

function isPrime(n) {
  if (n <= 1) return false;
  for (let i = 2; i * i <= n; i++) {
    if (n % i === 0) return false;
  }
  return true;
}

// Example usage:
let numbers = [2, 3, 4, 5, 6];
