Here is a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```
#include <iostream>
#include <fstream>
#include <string>
#include <map>

int main() {
    // Open the file
    std::ifstream file("example.txt"); // replace with your file name

    if (!file) {
        std::cerr << "Error opening file" << std::endl;
        return 1;
    }

    // Define the word to search for
    std::string targetWord = "example"; // replace with the word you want to search for

    // Create a map to store the word counts
    std::map<std::string, int> wordCounts;

    // Read the file line by line
    std::string line;
    while (std::getline(file, line)) {
        // Split the line into individual words
        std::istringstream iss(line);
        std::string word;
        while (iss >> word) {
            // Convert to lowercase to ignore case sensitivity
            std::transform(word.begin(), word.end(), word.begin(), ::tolower);

            // Increment the count for this word
            if (word == targetWord) {
                wordCounts[targetWord]++;
            }
        }
    }

    // Print the results
    std::cout << "Word '" << targetWord << "' occurs " << wordCounts[targetWord] << " times." << std::endl;

    return 0;
}
```
